3	import { env } from "@content-factory/env/web";
4	import type { Route } from "next";
5	import { useRouter } from "next/navigation";
6	import { useEffect, useState } from "react";
7	
8	import { type BrandProfile, loadBrandProfile } from "@/lib/brand-profile";
9	
10	import { VoiceoverButton } from "./voiceover-button";
11	
12	type JobStatus =
13		| "pending"
14		| "extracting"
15		| "researching"
16		| "scripting"
17		| "rendering"
18		| "voicing"
19		| "done"
20		| "failed";
21	
22	type Job = {
23		id: string;
24		status: JobStatus;
25		progress: number;
26		owner?: string;
27		name?: string;
28		error?: string;
29	};
30	
31	function ArrowLeftIcon() {
32		return (
33			<svg
34				aria-hidden="true"
35				width={13}
36				height={13}
37				viewBox="0 0 24 24"
38				fill="none"
39				stroke="currentColor"
40				strokeWidth={1.5}
41				strokeLinecap="round"
42				strokeLinejoin="round"
43			>
44				<path d="M19 12H5" />
45				<path d="M11 5l-7 7 7 7" />
46			</svg>
47		);
48	}
49	
50	function DownloadIcon() {
51		return (
52			<svg
53				aria-hidden="true"
54				width={14}
55				height={14}
56				viewBox="0 0 24 24"
57				fill="none"
58				stroke="currentColor"
59				strokeWidth={1.5}
60				strokeLinecap="round"
61				strokeLinejoin="round"
62			>
63				<path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
64				<path d="M7 10l5 5 5-5" />
65				<path d="M12 15V3" />
66			</svg>
67		);
68	}
69	
70	function RefreshIcon() {
71		return (
72			<svg
73				aria-hidden="true"
74				width={14}
75				height={14}
76				viewBox="0 0 24 24"
77				fill="none"
78				stroke="currentColor"
79				strokeWidth={1.5}
80				strokeLinecap="round"
81				strokeLinejoin="round"
82			>
83				<path d="M21 12a9 9 0 1 1-3-6.7" />
84				<path d="M21 4v5h-5" />
85			</svg>
86		);
87	}
88	
89	export function VideoCard({ jobId }: { jobId: string }) {
90		const router = useRouter();
91		const [job, setJob] = useState<Job | null>(null);
92		const [loadError, setLoadError] = useState<string | null>(null);
93		const [brand, setBrand] = useState<BrandProfile | null>(null);
94	
95		useEffect(() => {
96			setBrand(loadBrandProfile());
97		}, []);
98	
99		useEffect(() => {
100			let cancelled = false;
101			let timer: ReturnType<typeof setTimeout> | null = null;
102	
103			const tick = async () => {
104				try {
105					const response = await fetch(
106						`${env.NEXT_PUBLIC_SERVER_URL}/api/v1/video-jobs/${jobId}`,
107					);
108					if (!response.ok) {
109						throw new Error(`Server returned ${response.status}`);
110					}
111					const data = (await response.json()) as Job;
112					if (cancelled) return;
113					setJob(data);
114					if (data.status !== "done" && data.status !== "failed") {
115						timer = setTimeout(tick, 2000);
116					}
117				} catch (e) {
118					if (cancelled) return;
119					setLoadError(e instanceof Error ? e.message : "Failed to load job");
120				}
121			};
122	
123			void tick();
124			return () => {
125				cancelled = true;
126				if (timer) clearTimeout(timer);
127			};
128		}, [jobId]);
129	
130		const repoLabel = job?.owner && job?.name ? `${job.owner}/${job.name}` : "—";
131		const ready = job?.status === "done";
132		const failed = job?.status === "failed";
133		const videoSrc = `${env.NEXT_PUBLIC_SERVER_URL}/api/v1/video-jobs/${jobId}/video`;
134	
135		return (
136			<>
137				<header className="grid h-14 grid-cols-[1fr_auto_1fr] items-center border-[var(--color-border)] border-b bg-[var(--color-bg)] px-6">
138					<div className="flex items-center gap-[10px] text-[13px] text-[var(--color-text-muted)]">
139						<button
140							type="button"
141							onClick={() => router.push("/source" as Route)}
142							aria-label="Back to source"
143							className="inline-flex h-[26px] cursor-pointer items-center gap-[6px] rounded-md border border-[var(--color-border)] bg-transparent px-[8px] text-[var(--color-text-muted)] transition-[background-color,color] duration-[120ms] hover:bg-[var(--color-elev-1)] hover:text-[var(--color-text)]"
144						>
145							<ArrowLeftIcon />
146							<span>All projects</span>
147						</button>
148						<span className="text-[var(--color-text-dim)]">/</span>
149						<span className="mono text-[var(--color-text)]">{repoLabel}</span>
150					</div>
151					<div className="flex items-center justify-center gap-[10px] font-medium text-[14px] text-[var(--color-text)]">
152						{failed ? (
153							<span className="inline-block h-[6px] w-[6px] rounded-full bg-[var(--color-red)]" />
154						) : ready ? (
155							<span
156								className="inline-block h-[6px] w-[6px] rounded-full"
157								style={{
158									background: "var(--color-green)",
159									boxShadow: "0 0 0 3px rgba(45,106,79,0.18)",
160								}}
161							/>
162						) : (
163							<span className="brand-pulse inline-block h-[6px] w-[6px] rounded-full bg-[var(--color-magenta)]" />
164						)}
165						<span>
166							{failed
167								? "Generation failed"
168								: ready
169									? "Video ready"
170									: "Still rendering"}
171						</span>
172					</div>
173					<div className="flex items-center justify-end">
174						<span className="mono text-[11px] text-[var(--color-text-muted)]">
175							9:16 · 1080×1920
176						</span>
177					</div>
178				</header>
179	
180				<main className="mx-auto grid w-full max-w-[1280px] flex-1 grid-cols-[420px_1fr] gap-12 px-12 py-12">
181					<section className="flex flex-col items-start gap-4">
182						<div className="relative w-[360px]">
183							<div
184								aria-hidden
185								className="pointer-events-none absolute"
186								style={{
187									inset: "-60px",
188									borderRadius: "24px",
189									filter: "blur(2px)",
190									background:
191										"radial-gradient(circle at 0% 50%, rgba(229,38,124,0.14), transparent 38%), radial-gradient(circle at 100% 50%, rgba(229,38,124,0.10), transparent 38%)",
192								}}
193							/>
194							<div
195								className="relative aspect-[9/16] w-[360px] overflow-hidden rounded-md border bg-[#08080A]"
196								style={{ borderColor: "rgba(255,255,255,0.12)" }}
197							>
198								{ready ? (
199									// biome-ignore lint/a11y/useMediaCaption: hackathon demo, no captions yet
200									<video
201										data-testid="result-video"
202										controls
203										preload="metadata"
204										src={videoSrc}
205										className="h-full w-full object-cover"
