1	import { randomUUID } from "node:crypto";
2	import type { VideoScript } from "@content-factory/agent";
3	
4	export type JobStatus =
5		| "pending"
6		| "extracting"
7		| "researching"
8		| "scripting"
9		| "rendering"
10		| "voicing"
11		| "done"
12		| "failed";
13	
14	export interface Job {
15		id: string;
16		status: JobStatus;
17		progress: number;
18		message?: string;
19		script?: VideoScript;
20		videoPath?: string;
21		audioPath?: string;
22		error?: string;
23		ref?: string;
24		owner?: string;
25		name?: string;
26	}
27	
28	type Listener = (job: Job) => void;
29	
30	const jobs = new Map<string, Job>();
31	const listeners = new Map<string, Set<Listener>>();
32	
33	export function createJob(init: Partial<Job> = {}): Job {
34		const id = init.id ?? randomUUID();
35		const job: Job = {
36			id,
37			status: init.status ?? "pending",
38			progress: init.progress ?? 0,
39			message: init.message,
40			script: init.script,
41			videoPath: init.videoPath,
42			audioPath: init.audioPath,
43			error: init.error,
44			ref: init.ref,
45			owner: init.owner,
46			name: init.name,
47		};
48		jobs.set(id, job);
49		return job;
50	}
51	
52	export function getJob(id: string): Job | undefined {
53		return jobs.get(id);
54	}
55	
56	export function updateJob(id: string, patch: Partial<Job>): Job | undefined {
57		const current = jobs.get(id);
58		if (!current) return undefined;
59		const next: Job = { ...current, ...patch };
60		jobs.set(id, next);
61		const set = listeners.get(id);
62		if (set) {
63			for (const cb of set) {
64				try {
65					cb(next);
66				} catch (e) {
67					console.warn("job listener threw", e);
68				}
69			}
70		}
71		return next;
72	}
73	
74	export function subscribe(id: string, cb: Listener): () => void {
75		let set = listeners.get(id);
76		if (!set) {
