type StepState = "done" | "in-progress" | "pending";

type StepDef = {
	key: StepKey;
	name: string;
	pendingBody: string;
	activeBody: string;
	doneBody: string;
};

const STEPS: StepDef[] = [
	{
		key: "extracting",
		name: "extract_user_facing_changes",
